import json


class Payload(object):
    def __init__(self, command="ls"):
        self.command = command


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    return json.dumps(payload.__dict__).encode('utf-8')

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    try:
        # Get raw data from the request body
        data = request.get_data()
        if not data:
            return jsonify({"error": "No data provided"}), 400

        # Use safe_load to prevent arbitrary code execution (CWE-502)
        # yaml.load() is unsafe for untrusted input.
        parsed_data = yaml.safe_load(data)

        if parsed_data is None:
            return jsonify({"error": "YAML data is empty"}), 400

        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML: {str(e)}"}), 400
    except Exception:
        return jsonify({"error": "An unexpected error occurred"}), 500
